// src/pages/Termos/index.jsx

import React from 'react';

// [ADICIONADO] Importações do Header e Footer que estavam faltando


import { termsContent } from 'data/terms';
import 'styles/TextPage.css'; 

const TermsOfUsePage = () => {
  return (
    <>
      {/* [ADICIONADO] O componente Header no topo da página */}
      

      <main>
        <div className="container">
          <div className="text-content-page">

            <h1>{termsContent.title}</h1>
            <p className="last-updated">{termsContent.lastUpdated}</p>

            {termsContent.sections.map((section, index) => (
              <React.Fragment key={index}>
                <h2>{section.title}</h2>
                {section.content}
              </React.Fragment>
            ))}

          </div>
        </div>
      </main>

      {/* [ADICIONADO] O componente Footer no final da página */}
      <Footer />
    </>
  );
};

export default TermsOfUsePage;
